class Solution {
    public int minStartingIndex(String s, String pattern) {
        int m = pattern.length();
        int n = s.length();
        if (m > n) return -1;

        int[] lps = buildLPS(pattern);
        int[] zS = buildZ(s);
        int[] zP = buildZ(pattern);

        for (int i = 0; i <= n - m; i++) {
            int mismatch = 0;
            int j = 0;
            while (j < m) {
                if (s.charAt(i + j) == pattern.charAt(j)) {
                    j++;
                } else {
                    mismatch++;
                    if (mismatch > 1) break;
                    int skip = lps[j];
                    j = Math.max(j, skip);
                }
            }
            if (mismatch <= 1) return i;
        }
        return -1;
    }

    private int[] buildLPS(String pattern) {
        int m = pattern.length();
        int[] lps = new int[m];
        int len = 0;
        int i = 1;
        while (i < m) {
            if (pattern.charAt(i) == pattern.charAt(len)) {
                len++;
                lps[i] = len;
                i++;
            } else {
                if (len != 0) {
                    len = lps[len - 1];
                } else {
                    lps[i] = 0;
                    i++;
                }
            }
        }
        return lps;
    }

    private int[] buildZ(String s) {
        int n = s.length();
        int[] z = new int[n];
        int l = 0, r = 0;
        for (int i = 1; i < n; i++) {
            if (i <= r) {
                z[i] = Math.min(r - i + 1, z[i - l]);
            }
            while (i + z[i] < n && s.charAt(z[i]) == s.charAt(i + z[i])) {
                z[i]++;
            }
            if (i + z[i] - 1 > r) {
                l = i;
                r = i + z[i] - 1;
            }
        }
        z[0] = n;
        return z;
    }
}
